{
  "name": "Khmer Spell Check & Grammar Pro",
  "description": "An advanced Khmer language spelling and grammar assistant powered by Gemini AI, providing real-time corrections and linguistic suggestions.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SpellCorrection {
  originalText: string;
  suggestedText: string;
  reason: string;
  type: 'spelling' | 'grammar' | 'style';
}

export interface AnalysisResult {
  corrections: SpellCorrection[];
  summary: string;
  isCorrect: boolean;
  improvedText: string;
}

export interface HistoryItem {
  id: string;
  timestamp: number;
  text: string;
  result: AnalysisResult;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const SCHEMA = {
  type: Type.OBJECT,
  properties: {
    isCorrect: {
      type: Type.BOOLEAN,
      description: "True if the text has no spelling or grammar errors.",
    },
    improvedText: {
      type: Type.STRING,
      description: "The complete corrected version of the text.",
    },
    summary: {
      type: Type.STRING,
      description: "A short summary of the linguistic feedback in Khmer.",
    },
    corrections: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          originalText: { type: Type.STRING },
          suggestedText: { type: Type.STRING },
          reason: { type: Type.STRING, description: "Why this correction is suggested (in Khmer)." },
          type: { 
            type: Type.STRING, 
            description: "spelling, grammar, or style" 
          }
        },
        required: ["originalText", "suggestedText", "reason", "type"]
      }
    }
  },
  required: ["isCorrect", "improvedText", "summary", "corrections"]
};

export const analyzeKhmerText = async (text: string): Promise<AnalysisResult> => {
  if (!text.trim()) {
    throw new Error("Text is empty");
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Please analyze the following Khmer text for spelling, grammar, and style errors. Provide a list of specific corrections and an overall improved version.

      Text to analyze: "${text}"`,
      config: {
        systemInstruction: "You are a professional Khmer linguist and editor. Your goal is to help users write perfect Khmer. Identify errors accurately and provide helpful explanations in Khmer language.",
        responseMimeType: "application/json",
        responseSchema: SCHEMA,
      },
    });

    const result = JSON.parse(response.text);
    return result as AnalysisResult;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';
import { SpellCorrection } from '../types';

interface CorrectionCardProps {
  correction: SpellCorrection;
  onApply: (correction: SpellCorrection) => void;
}

const CorrectionCard: React.FC<CorrectionCardProps> = ({ correction, onApply }) => {
  const typeColors = {
    spelling: 'bg-red-100 text-red-700 border-red-200',
    grammar: 'bg-amber-100 text-amber-700 border-amber-200',
    style: 'bg-blue-100 text-blue-700 border-blue-200',
  };

  return (
    <div className="bg-white border border-slate-200 rounded-xl p-4 shadow-sm hover:shadow-md transition-all mb-3">
      <div className="flex justify-between items-start mb-2">
        <span className={`text-xs font-bold px-2 py-1 rounded-full uppercase tracking-wider ${typeColors[correction.type]}`}>
          {correction.type}
        </span>
        <button 
          onClick={() => onApply(correction)}
          className="text-indigo-600 hover:text-indigo-800 text-sm font-medium transition-colors"
        >
          អនុវត្ត (Apply)
        </button>
      </div>

      <div className="flex items-center gap-2 mb-2">
        <span className="line-through text-slate-400 khmer-font">{correction.originalText}</span>
        <span className="text-slate-300">→</span>
        <span className="text-green-600 font-bold khmer-font">{correction.suggestedText}</span>
      </div>

      <p className="text-sm text-slate-600 khmer-font leading-relaxed">
        {correction.reason}
      </p>
    </div>
  );
};

export default CorrectionCard;

import React, { useState, useCallback, useEffect } from 'react';
import { analyzeKhmerText } from './services/geminiService';
import { AnalysisResult, HistoryItem, SpellCorrection } from './types';
import CorrectionCard from './components/CorrectionCard';

const App: React.FC = () => {
