      id: Date.now().toString(),
      timestamp: Date.now(),
      text,
      result: analysis
    };
    const updatedHistory = [newItem, ...history].slice(0, 10);
    setHistory(updatedHistory);
    localStorage.setItem('khmer_spellcheck_history', JSON.stringify(updatedHistory));
  }, [history]);

