                <div className={`p-4 rounded-xl mb-4 border ${result.isCorrect ? 'bg-green-50 border-green-200' : 'bg-indigo-50 border-indigo-200'}`}>
                  <p className="font-bold text-slate-800 khmer-font mb-1">
