                  </p>
                  <p className="text-sm text-slate-600 khmer-font">
                    {result.summary}
                  </p>
                </div>

                <div className="max-h-[60vh] overflow-y-auto pr-2 space-y-3 custom-scrollbar">
                  {result.corrections.map((c, i) => (
                    <CorrectionCard 
                      key={i} 
                      correction={c} 
                      onApply={handleApplySingle} 
                    />
                  ))}
                  {result.corrections.length === 0 && !result.isCorrect && (
                    <p className="text-center text-slate-500 py-4 khmer-font italic">
                      មិនមានចំណុចជាក់លាក់ដែលត្រូវកែទេ ប៉ុន្តែមានការណែនាំជាទូទៅ។
                    </p>
                  )}
