              </div>
            )}
          </div>

          {/* History / Tips */}
          <div className="bg-white rounded-2xl shadow-lg border border-slate-200 p-6">
            <h3 className="text-lg font-bold text-slate-800 mb-4 khmer-font">ប្រវត្តិថ្មីៗ</h3>
            {history.length > 0 ? (
              <div className="space-y-4">
                {history.map((item) => (
                  <div 
                    key={item.id} 
                    onClick={() => {
                      setInputText(item.text);
                      setResult(item.result);
                    }}
                    className="p-3 bg-slate-50 rounded-lg hover:bg-slate-100 cursor-pointer transition-colors border border-transparent hover:border-slate-200"
                  >
                    <p className="text-sm khmer-font line-clamp-2 text-slate-600 mb-1">
                      {item.text}
                    </p>
                    <p className="text-[10px] text-slate-400 font-mono">
                      {new Date(item.timestamp).toLocaleString('km-KH')}
                    </p>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-sm text-slate-400 khmer-font text-center">មិនទាន់មានប្រវត្តិប្រើប្រាស់ទេ។</p>
            )}
          </div>
        </aside>
      </main>

      {/* Footer Branding */}
      <footer className="mt-12 text-slate-400 text-sm khmer-font text-center pb-8">
        <p>&copy; {new Date().getFullYear()} ពិនិត្យអក្ខរាវិរុទ្ធខ្មែរ PRO - បង្កើតឡើងដោយការយកចិត្តទុកដាក់សម្រាប់ភាសាខ្មែរ</p>
      </footer>
    </div>
  );
};

