import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SCHEMA = {
  type: Type.OBJECT,
  properties: {
    isCorrect: {
      type: Type.BOOLEAN,
      description: "True if the text has no spelling or grammar errors.",
    },
    improvedText: {
      type: Type.STRING,
      description: "The complete corrected version of the text.",
    },
    summary: {
      type: Type.STRING,
      description: "A short summary of the linguistic feedback in Khmer.",
    },
    corrections: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          originalText: { type: Type.STRING },
          suggestedText: { type: Type.STRING },
          reason: { type: Type.STRING, description: "Why this correction is suggested (in Khmer)." },
          type: { 
            type: Type.STRING, 
            description: "spelling, grammar, or style" 
          }
        },
        required: ["originalText", "suggestedText", "reason", "type"]
      }
    }
  },
  required: ["isCorrect", "improvedText", "summary", "corrections"]
};

export const analyzeKhmerText = async (text: string): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    throw new Error("MISSING_API_KEY");
  }

  if (!text.trim()) {
    throw new Error("EMPTY_TEXT");
  }

  // Always create a fresh instance with the current API key
  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Please analyze the following Khmer text for spelling, grammar, and style errors. Provide a list of specific corrections and an overall improved version.

      Text to analyze: "${text}"`,
      config: {
        systemInstruction: "You are a professional Khmer linguist and editor. Your goal is to help users write perfect Khmer. Identify errors accurately and provide helpful explanations in Khmer language. Always ensure the output is valid JSON according to the schema.",
        responseMimeType: "application/json",
        responseSchema: SCHEMA,
      },
    });

    const result = JSON.parse(response.text);
    return result as AnalysisResult;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.status === 401 || error.status === 403 || (error.message && error.message.includes('API key'))) {
      throw new Error("INVALID_API_KEY");
    }
    throw error;
  }
};

