import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SCHEMA = {
  type: Type.OBJECT,
  properties: {
    isCorrect: {
      type: Type.BOOLEAN,
      description: "True if the text has no spelling or grammar errors.",
    },
    improvedText: {
      type: Type.STRING,
      description: "The complete corrected version of the text.",
    },
    summary: {
      type: Type.STRING,
      description: "A short summary of the linguistic feedback in Khmer.",
    },
    corrections: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          originalText: { type: Type.STRING },
          suggestedText: { type: Type.STRING },
          reason: { type: Type.STRING, description: "Why this correction is suggested (in Khmer)." },
          type: { 
            type: Type.STRING, 
            description: "spelling, grammar, or style" 
          }
        },
        required: ["originalText", "suggestedText", "reason", "type"]
      }
    }
  },
  required: ["isCorrect", "improvedText", "summary", "corrections"]
};

export const analyzeKhmerText = async (text: string): Promise<AnalysisResult> => {
  // Always initialize with the key from process.env.API_KEY as required.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  if (!text.trim()) {
    throw new Error("EMPTY_TEXT");
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{
        parts: [{
          text: `សូមពិនិត្យអក្ខរាវិរុទ្ធ និងវេយ្យាករណ៍អត្ថបទខ្មែរខាងក្រោម៖\n\n"${text}"`
        }]
      }],
      config: {
        systemInstruction: "You are a professional Khmer language editor. Analyze the input for spelling mistakes, grammatical errors, and stylistic improvements. Provide feedback in Khmer. Your output must strictly follow the provided JSON schema.",
        responseMimeType: "application/json",
        responseSchema: SCHEMA,
      },
    });

    const result = JSON.parse(response.text || "{}");
    return result as AnalysisResult;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    // Throw standard error types for the UI to handle
    if (error.message?.includes('API key') || error.status === 401 || error.status === 403) {
      throw new Error("MISSING_API_KEY");
    }
    throw new Error("API_FAILURE");
  }
};

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { analyzeKhmerText } from './services/geminiService';
import { AnalysisResult, HistoryItem, SpellCorrection } from './types';
import CorrectionCard from './components/CorrectionCard';

const App: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [error, setError] = useState<{ message: string; type: 'auth' | 'general' } | null>(null);
  const [needsKey, setNeedsKey] = useState(false);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const highlightLayerRef = useRef<HTMLDivElement>(null);

  // Check for API Key or AI Studio session on load
  useEffect(() => {
    const checkKeyStatus = async () => {
      // Check if API_KEY is present in the environment
      if (process.env.API_KEY && process.env.API_KEY !== "") {
        setNeedsKey(false);
        return;
      }

      // If not in process.env, check if we are in an environment with AI Studio context
      if (typeof window !== 'undefined' && (window as any).aistudio) {
        try {
          const hasKey = await (window as any).aistudio.hasSelectedApiKey();
          setNeedsKey(!hasKey);
        } catch (e) {
          setNeedsKey(true);
        }
      } else {
        // External hosting (like Vercel) without the environment variable set
        setNeedsKey(true);
      }
    };

    checkKeyStatus();

    const savedHistory = localStorage.getItem('khmer_spellcheck_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const handleOpenKeyDialog = async () => {
    if (typeof window !== 'undefined' && (window as any).aistudio) {
      await (window as any).aistudio.openSelectKey();
      setNeedsKey(false);
      setError(null);
    } else {
      alert("សម្រាប់ Vercel: សូមបន្ថែម Environment Variable ឈ្មោះ API_KEY ក្នុង Settings នៃ Dashboard របស់អ្នក រួចធ្វើការ Redeploy។");
    }
  };

  const handleScroll = (e: React.UIEvent<HTMLTextAreaElement>) => {
    if (highlightLayerRef.current) {
      highlightLayerRef.current.scrollTop = e.currentTarget.scrollTop;
    }
  };

  const saveToHistory = useCallback((text: string, analysis: AnalysisResult) => {
    const newItem: HistoryItem = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      text,
      result: analysis
    };
    const updatedHistory = [newItem, ...history].slice(0, 10);
    setHistory(updatedHistory);
    localStorage.setItem('khmer_spellcheck_history', JSON.stringify(updatedHistory));
  }, [history]);

  const handleCheck = async () => {
    if (!inputText.trim()) return;

    setIsAnalyzing(true);
    setError(null);
    try {
      const data = await analyzeKhmerText(inputText);
      setResult(data);
      saveToHistory(inputText, data);
    } catch (err: any) {
      console.error("Check Error:", err);
      if (err.message === 'MISSING_API_KEY' || err.message === 'INVALID_API_KEY') {
        setNeedsKey(true);
        setError({
          type: 'auth',
          message: 'រកមិនឃើញ API Key៖ សូមពិនិត្យមើលការកំណត់ក្នុង Vercel Dashboard ឬចុចប៊ូតុងខាងក្រោម។'
        });
      } else {
        setError({
          type: 'general',
          message: 'មានបញ្ហាបច្ចេកទេស។ សូមព្យាយាមម្តងទៀតនៅពេលក្រោយ។'
        });
      }
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleApplyAll = () => {
    if (result) {
      setInputText(result.improvedText);
      setResult(null);
    }
  };

  const handleApplySingle = (correction: SpellCorrection) => {
    const escaped = correction.originalText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const newText = inputText.replace(new RegExp(escaped, 'g'), correction.suggestedText);
    setInputText(newText);

    if (result) {
      const remaining = result.corrections.filter(c => c.originalText !== correction.originalText);
      setResult({
        ...result,
        corrections: remaining,
        isCorrect: remaining.length === 0,
        improvedText: result.improvedText // Keep this or update it if needed
      });
    }
  };

  const renderHighlightedText = () => {
    if (!result || result.corrections.length === 0) return inputText;

    let html = inputText
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');

    const sorted = [...result.corrections].sort((a, b) => b.originalText.length - a.originalText.length);

    sorted.forEach(c => {
      const original = c.originalText.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
      if (original) {
        // Use a global replacement to highlight all instances
        const regex = new RegExp(original, 'g');
        html = html.replace(regex, `<span class="highlight-error">${original}</span>`);
      }
    });

    return <div dangerouslySetInnerHTML={{ __html: html + '\n' }} />;
  };

  return (
    <div className="min-h-screen bg-transparent flex flex-col items-center py-8 px-4 sm:px-6">
      <header className="max-w-5xl w-full text-center mb-10">
        <div className="relative inline-block">
          <div className="khmer-ancient-frame">
            <div className="kbach-corner tl-kbach" />
            <div className="kbach-corner tr-kbach" />
            <div className="kbach-corner bl-kbach" />
            <div className="kbach-corner br-kbach" />
            <div className="kbach-center top-center" />
            <div className="kbach-center bottom-center" />
            <div className="frame-inner-border" />
            <h1 className="text-3xl md:text-5xl font-black text-white niroth-font relative z-10 px-4">
              កម្មវិធីពិនិត្យអក្ខរាវិរុទ្ធ
            </h1>
          </div>
        </div>
        <p className="text-blue-400 mt-6 khmer-font text-lg tracking-wide uppercase shadow-sm">
          {"ជំនួយការភាសាខ្មែរឆ្លាតវៃ (Gemini AI)"}
        </p>
      </header>

      <main className="max-w-6xl w-full grid grid-cols-1 lg:grid-cols-12 gap-8">
        <section className="lg:col-span-8 space-y-4">
          {needsKey && (
            <div className="bg-amber-500/10 backdrop-blur-md border border-amber-500/50 p-6 rounded-3xl flex flex-col sm:flex-row gap-5 items-center animate-in fade-in duration-500">
              <div className="bg-amber-500 p-3 rounded-2xl text-white shadow-lg">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
              </div>
              <div className="flex-1 text-center sm:text-left">
                <h4 className="text-amber-200 font-bold khmer-font text-lg">{"មិនទាន់មាន API Key សម្រាប់ Vercel"}</h4>
                <p className="text-amber-100/70 text-sm khmer-font leading-relaxed">
                  {"សូមកំណត់ Environment Variable ឈ្មោះ API_KEY ក្នុង Settings នៃ Vercel Dashboard របស់អ្នក ដើម្បីឱ្យកម្មវិធីដំណើរការបាន។"}
                </p>
              </div>
              <button 
                onClick={handleOpenKeyDialog}
                className="whitespace-nowrap px-6 py-2 bg-amber-500 hover:bg-amber-600 text-white rounded-xl font-bold khmer-font transition-all shadow-lg active:scale-95"
              >
                {"ភ្ជាប់ AI ឥឡូវនេះ"}
              </button>
            </div>
          )}

          <div className="bg-white/95 backdrop-blur-md rounded-3xl shadow-2xl overflow-hidden border border-white/20 flex flex-col min-h-[550px] relative">
            <div className="bg-slate-50/80 border-b border-slate-200 px-6 py-4 flex justify-between items-center">
              <div className="flex gap-4 text-xs font-bold uppercase tracking-widest text-slate-500">
                <div className="flex items-center gap-1">
                  <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                  <span>{"តួអក្សរ: "}{inputText.length}</span>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => setInputText('')} className="p-2 hover:bg-red-50 hover:text-red-500 rounded-xl transition-all" title="Clear All">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
              </div>
            </div>

            <div className="editor-container">
              <div ref={highlightLayerRef} className="editor-layer khmer-font custom-scrollbar">{renderHighlightedText()}</div>
              <textarea
                ref={textareaRef}
                className="editor-textarea khmer-font custom-scrollbar"
                placeholder="សូមសរសេរអត្ថបទនៅទីនេះ..."
                value={inputText}
                onScroll={handleScroll}
                onChange={(e) => {
                  setInputText(e.target.value);
                  if (result) setResult(null);
                }}
              />
            </div>

            <div className="p-5 bg-slate-50 border-t border-slate-200 flex justify-end gap-3 sticky bottom-0 z-30">
               {result && !result.isCorrect && (
                <button onClick={handleApplyAll} className="px-6 py-3 bg-teal-600 hover:bg-teal-700 text-white rounded-2xl font-bold transition-all shadow-lg khmer-font">
                  {"កែតម្រូវទាំងអស់"}
                </button>
              )}
              <button 
                onClick={handleCheck}
                disabled={isAnalyzing || !inputText.trim() || (needsKey && !process.env.API_KEY)}
                className={`px-12 py-3 rounded-2xl font-bold transition-all shadow-xl flex items-center gap-3 khmer-font ${
                  isAnalyzing || !inputText.trim() || (needsKey && !process.env.API_KEY)
                  ? 'bg-slate-300 text-slate-500 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-500/20'
                }`}
              >
                {isAnalyzing ? (
                  <><span className="animate-spin rounded-full h-4 w-4 border-2 border-white/30 border-t-white"></span>{"កំពុងពិនិត្យ..."}</>
                ) : 'ពិនិត្យអត្ថបទ'}
              </button>
            </div>
          </div>
          {error?.type === 'general' && <div className="p-4 bg-red-500/10 backdrop-blur-md border border-red-500/30 text-red-400 rounded-2xl khmer-font text-sm">{error.message}</div>}
        </section>

        <aside className="lg:col-span-4 space-y-6">
          <div className="bg-white/95 backdrop-blur-md rounded-3xl shadow-xl border border-white/20 p-6 min-h-[450px] flex flex-col">
            <h3 className="text-xl font-bold text-slate-800 mb-6 khmer-font flex items-center gap-3">
              <div className="p-2 bg-indigo-50 rounded-xl text-indigo-600">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
              </div>
              {"លទ្ធផលវិភាគ"}
            </h3>

            {!result && !isAnalyzing && (
              <div className="flex-1 flex flex-col items-center justify-center text-center opacity-40">
                <p className="khmer-font text-slate-500">{"មិនទាន់មានទិន្នន័យ"}</p>
              </div>
            )}

            {isAnalyzing && (
              <div className="space-y-5">
                {[1,2,3].map(i => (
                  <div key={i} className="animate-pulse space-y-2">
                    <div className="h-4 bg-slate-100 rounded-full w-2/5"></div>
                    <div className="h-24 bg-slate-50 rounded-2xl"></div>
                  </div>
                ))}
              </div>
            )}

            {result && (
              <div className="space-y-5 animate-in fade-in duration-300">
                <div className={`p-4 rounded-2xl border ${result.isCorrect ? 'bg-green-50 border-green-200 text-green-800' : 'bg-indigo-50 border-indigo-200 text-indigo-800'}`}>
                  <p className="font-bold khmer-font text-base mb-1">{result.isCorrect ? '✨ ត្រឹមត្រូវល្អ!' : '📝 រកឃើញចំណុចគួរកែ'}</p>
                  <p className="text-sm khmer-font leading-relaxed">{result.summary}</p>
                </div>
                <div className="space-y-3 overflow-y-auto max-h-[450px] pr-2 custom-scrollbar">
                  {result.corrections.map((c, idx) => (
                    <CorrectionCard key={idx} correction={c} onApply={handleApplySingle} />
                  ))}
                </div>
              </div>
            )}
          </div>
        </aside>
      </main>

      <footer className="mt-16 text-center text-slate-500 text-sm khmer-font pb-12">
        <p>{"© "}{new Date().getFullYear()}{" កម្មវិធីពិនិត្យអក្ខរាវិរុទ្ធខ្មែរ"}</p>
      </footer>
    </div>
  );
};

export default App;
